function executeSkill(context) {
    const sourcePiece = context.piece;
    if (!sourcePiece.statusTags || sourcePiece.statusTags.length === 0) {
      return { message: '没有状态标签', success: false };
    }
    const blizzardStatus = sourcePiece.statusTags.find(effect => effect.type === 'blizzard');
    if (!blizzardStatus) {
      return { message: '没有暴风雪状态', success: false };
    }
    const centerX = blizzardStatus.value;
    const centerY = blizzardStatus.extraValue;
    const damageValue = blizzardStatus.damage;
    if (centerX === undefined || centerY === undefined || damageValue === undefined) {
      return { message: '暴风雪状态数据不完整', success: false };
    }
    if (context.playerId === sourcePiece.ownerPlayerId) {
      return { message: '暴风雪只在对方回合结束时触发', success: false };
    }
    const radius = 1;
    const enemiesInArea = context.battle.pieces.filter(piece => {
      if (piece.ownerPlayerId === sourcePiece.ownerPlayerId) return false;
      if (piece.currentHp <= 0) return false;
      const distanceX = Math.abs(piece.x - centerX);
      const distanceY = Math.abs(piece.y - centerY);
      return distanceX <= radius && distanceY <= radius;
    });
    // 传入数组：beforeDamageDealt 只触发一次，buff 只消耗一次
    const dmgResult = dealDamage(sourcePiece, enemiesInArea, damageValue, 'magical', context.battle, 'blizzard');
    const totalDamage = dmgResult.totalDamage || 0;
    // 对每个受击目标施加冰冻（独立逐个处理）
    enemiesInArea.forEach(function(enemy, i) {
      const r = dmgResult.results && dmgResult.results[i];
      if (r && r.success) {
        const statusId = 'freeze-' + Date.now() + '-' + enemy.instanceId;
        addStatusEffectById(enemy.instanceId, { id: statusId, type: 'freeze', currentDuration: 1, intensity: 1 });
        addRuleById(enemy.instanceId, 'rule-freeze-prevent-move');
        addRuleById(enemy.instanceId, 'rule-freeze-prevent-skill');
        addSkillById(enemy.instanceId, 'freeze-prevent');
        enemy.showFreezeEffect = true;
      }
    });
    const hitEnemies = enemiesInArea.filter(function(e, i) { return dmgResult.results && dmgResult.results[i] && dmgResult.results[i].success; });
    if (!context.battle.effects) { context.battle.effects = []; }
    for (let x = centerX - radius; x <= centerX + radius; x++) {
      for (let y = centerY - radius; y <= centerY + radius; y++) {
        context.battle.effects.push({ type: 'blizzard', position: { x, y }, duration: 1, zIndex: 999, showOnUI: true });
      }
    }
    removeStatusEffectById(sourcePiece.instanceId, blizzardStatus.id);
    removeRuleById(sourcePiece.instanceId, 'rule-blizzard-active');
    removeSkillById(sourcePiece.instanceId, 'blizzard-damage');
    let message = sourcePiece.name + '的暴风雪效果（中心坐标：(' + centerX + ',' + centerY + ')）';
    if (hitEnemies.length > 0) {
      message += '对' + hitEnemies.map(function(e) { return e.name; }).join('、') + '造成了' + totalDamage + '点伤害并使其冰冻';
    } else {
      message += '没有对任何敌人造成伤害';
    }
    return { message: message, success: true, showUIEffects: true };
  }

blizzard.code:
function executeSkill(context) {
  const sourcePiece = context.piece;
  const damageValue = sourcePiece.attack * context.skill.powerMultiplier;
  const targetPosition = selectTarget({ type: 'grid', range: 10, filter: 'all' });
  if (!targetPosition || targetPosition.needsTargetSelection) {
    return targetPosition;
  }
  // 给自身添加statusTag存储暴风雪中心位置和伤害
  // 同时传入relatedRules，让restorePieceRules能在API传输后恢复规则
  if (typeof addStatusEffectById === 'function') {
    const statusId = 'blizzard-' + Date.now();
    addStatusEffectById(sourcePiece.instanceId, {
      id: statusId,
      type: 'blizzard',
      currentDuration: 2,
      intensity: 1,
      value: targetPosition.x,
      extraValue: targetPosition.y,
      damage: damageValue,
      relatedRules: ['rule-blizzard-active']
    });
  }
  // 给自身添加规则，在对方回合结束时触发
  if (typeof addRuleById === 'function') {
    addRuleById(sourcePiece.instanceId, 'rule-blizzard-active');
  }
  // 给自身添加暴风雪效果技能
  if (typeof addSkillById === 'function') {
    addSkillById(sourcePiece.instanceId, 'blizzard-damage');
  }
  return {
    message: sourcePiece.name + '使用了暴风雪，在(' + targetPosition.x + ',' + targetPosition.y + ')创造了暴风雪区域，将在对方回合结束时对3x3格范围内的敌人造成' + damageValue + '点伤害并使其冰冻',
    success: true
  };
}

